import { customers } from "@/features/customers/api/customers-data";
import { CustomerEquityChart } from "@/features/customers/components/CustomerEquityChart";
import { AIStrip } from "@/components/shared/AIStrip";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import "./customers.css";

const ACCENT_VAR: Record<string, string> = {
  red: "#d64545",
  vip: "var(--vip)",
  finance: "var(--d-finance)",
};

export default function CustomersPage() {
  const { ai, hero, equityPanel, kpis, equity, trajectory, healthyBase, fiveForces, acquisitionSource, backDriver } = customers;

  return (
    <div className="customers-room">
      <div className="dept-wrap">
        <DeptHeader
          dept="customers"
          title="Customers Overview"
          meta={<><span className="live">{customers.livePill}</span> · {customers.meta}</>}
          actions={
            <>
              <button className="btn-util primary">+ Add segment</button>
              <button className="btn-util primary">Recover at-risk →</button>
            </>
          }
        />
        <PeriodTabs labels={["MTD", "Last 30 days", "Last 6 months", "Last 12 months", "Custom"]} />

        {/* AI STRIP */}
        <AIStrip
          label={ai.label}
          meta={{ confidence: ai.confidence, sources: ai.sources, syncedAgo: ai.syncedAgo }}
          cards={ai.cards.map((c) => ({ ...c, accent: ACCENT_VAR[c.accent] ?? "var(--cream)" }))}
        />

        {/* HERO + EQUITY TELEMETRY */}
        <div className="dept-hero-row">
          <div className="dept-hero" data-d="customers">
            <div className="dept-hero-tag">
              <span className="live">MTD</span> · Net Customer Equity added
            </div>
            <div className="dept-hero-value">{hero.value}</div>
            <div className="dept-hero-sub">{hero.sub}</div>
            <div className="dept-hero-stats">
              {hero.stats.map((s, i) => (
                <div key={i} className="dept-hero-stat">
                  <div className="lbl">{s.label}</div>
                  <div className="val">{s.value}</div>
                </div>
              ))}
            </div>
          </div>

          <div className="telemetry-panel">
            <div className="telemetry-head">
              <div className="telemetry-label">{equityPanel.label}</div>
              <div className="telemetry-pulse-wrap">
                <span className="telemetry-meta">{equityPanel.livePill}</span>
                <span className="dot-pulse" />
              </div>
            </div>
            <div className="telemetry-rows">
              {equityPanel.rows.map((r, i) => (
                <div key={i} className="telemetry-row">
                  <div className="lbl">{r.label}</div>
                  <div className="val">
                    {r.value}
                    {r.valueUnit && <span className="val-unit">{r.valueUnit}</span>}
                  </div>
                  <div className={`delta ${r.deltaState ?? ""}`}>{r.delta}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* 6-CELL KPI STRIP */}
        <div className="ops-kpi-row">
          {kpis.map((k, i) => (
            <div key={i} className="ops-kpi-cell">
              <div className="lbl">{k.label}</div>
              <div className={`val${k.state ? " " + k.state : ""}`}>{k.value}</div>
              <div className="sub">{k.sub}</div>
            </div>
          ))}
        </div>

        {/* CUSTOMER EQUITY CHART */}
        <div className="finsit-card">
          <div className="finsit-head">
            <div className="finsit-lead">
              <div className="finsit-title">{equity.title}</div>
              <div className="finsit-k">{equity.kicker}</div>
              <div className="finsit-hero">
                <span className="finsit-big">{equity.hero}</span>
                <span className="finsit-delta" style={{ color: "#d64545" }}>{equity.delta}</span>
              </div>
              <div className="finsit-readline">
                <span className="finsit-ro">
                  <span className="l">Net this month</span>
                  <span className="v green">{equity.netThisMonth}</span>
                  <span className="s">{equity.netNote}</span>
                </span>
                <span className="finsit-ro">
                  <span className="l">Monthly churn</span>
                  <span className="v amber">{equity.monthlyChurn}</span>
                  <span className="s">{equity.churnNote}</span>
                </span>
                <span className="finsit-ro">
                  <span className="l">Next 90 days</span>
                  <span className="v" style={{ color: "#d64545" }}>{equity.next90}</span>
                  <span className="s">{equity.next90Note}</span>
                </span>
              </div>
            </div>
            <div className="finsit-cluster">
              <div className="finsit-live">
                <span className="finsit-live-dot" />
                <span className="finsit-lt">Live <span>· synced 2 min ago</span></span>
              </div>
              <div className="finsit-verified">
                <svg width="18" height="18" viewBox="0 0 22 22" fill="none">
                  <rect x="2.5" y="2.5" width="17" height="17" rx="1" stroke="#b88a2a" strokeWidth="1.4" strokeDasharray="3 2.5" />
                  <path d="M5.5 13 Q8 6.5 11 11 T16.5 9" stroke="#b88a2a" strokeWidth="1.6" fill="none" strokeLinecap="round" />
                </svg>
                <div className="finsit-vt">
                  <b>Modeled estimate</b>
                  <span>expected value · 2,140 customers</span>
                </div>
              </div>
            </div>
          </div>

          <CustomerEquityChart />

          <div className="finsit-legend">
            <span className="finsit-leg"><span className="sw cash" />Customer equity (actual)</span>
            <span className="finsit-leg"><span className="sw proj" />Projected</span>
            <span className="finsit-leg"><span className="sw hold" />If retention held</span>
            <span className="finsit-leg"><span className="sw risk" />Equity at risk</span>
          </div>
        </div>

        {/* STATUS ROW */}
        <div className="status-row">
          <div className="status-card">
            <div className="status-head">
              <div className="status-label">{trajectory.label}</div>
              <div className="status-state pos">✓ {trajectory.state}</div>
            </div>
            <div className="status-main">
              <div className="status-val">
                {trajectory.pctVal}
                <span className="status-pct">{trajectory.pctUnit}</span>
              </div>
              <div className="status-sub">{trajectory.sub}</div>
            </div>
            <div className="position-bar">
              <div className="pb-track">
                <div className="pb-zones">
                  {trajectory.zones.map((z, i) => (
                    <div key={i} className="pb-zone" data-zone={z.kind} style={{ width: `${z.widthPct}%` }} />
                  ))}
                </div>
                <div className="pb-threshold" style={{ left: `${trajectory.thresholdPct}%` }}>
                  <span className="pb-threshold-lbl">{trajectory.thresholdLabel}</span>
                </div>
                <div className="pb-marker" style={{ left: `${trajectory.markerPct}%` }}>
                  <span className="pb-marker-val">{trajectory.markerLabel}</span>
                </div>
              </div>
              <div className="pb-axis">
                <span>{trajectory.axisStart}</span>
                <span>{trajectory.axisEnd}</span>
              </div>
            </div>
            <div className="status-forecast">
              <span className="forecast-arrow">→</span>
              <span className="forecast-text" dangerouslySetInnerHTML={{ __html: trajectory.forecast }} />
            </div>
          </div>

          <div className="status-card">
            <div className="status-head">
              <div className="status-label">{healthyBase.label}</div>
              <div className={`status-state ${healthyBase.stateKind}`}>⚠ {healthyBase.state}</div>
            </div>
            <div className="status-main">
              <div className="status-val">
                {healthyBase.pctVal}
                <span className="status-pct">{healthyBase.pctUnit}</span>
              </div>
              <div className="status-sub">{healthyBase.sub}</div>
            </div>
            <div className="position-bar">
              <div className="pb-track">
                <div className="pb-zones">
                  {healthyBase.zones.map((z, i) => (
                    <div key={i} className="pb-zone" data-zone={z.kind} style={{ width: `${z.widthPct}%` }} />
                  ))}
                </div>
                <div className="pb-threshold" style={{ left: `${healthyBase.thresholdPct}%` }}>
                  <span className="pb-threshold-lbl">{healthyBase.thresholdLabel}</span>
                </div>
                <div className="pb-marker" style={{ left: `${healthyBase.markerPct}%` }}>
                  <span className="pb-marker-val">{healthyBase.markerLabel}</span>
                </div>
              </div>
              <div className="pb-axis">
                <span>{healthyBase.axisStart}</span>
                <span>{healthyBase.axisEnd}</span>
              </div>
            </div>
            <div className="status-forecast">
              <span className="forecast-arrow">→</span>
              <span className="forecast-text" dangerouslySetInnerHTML={{ __html: healthyBase.forecast }} />
            </div>
          </div>
        </div>

        {/* FIVE FORCES */}
        <SectionLabel>The five forces on your customer equity</SectionLabel>
        <div className="drivers-row">
          {fiveForces.map((d, i) => (
            <div key={i} className="driver" style={{ ["--dc" as string]: d.accent } as React.CSSProperties}>
              <div className="driver-tag">{d.tag}</div>
              <div className="driver-name">{d.name}</div>
              <div className={`driver-num ${d.numState}`}>{d.num}</div>
              <div className="driver-read">{d.read}</div>
              <div className="driver-link">{d.link}</div>
            </div>
          ))}
        </div>

        {/* WHERE THEY COME FROM / WHAT BRINGS THEM BACK */}
        <SectionLabel>Where customers come from · what brings them back</SectionLabel>
        <div className="src-row">
          {[acquisitionSource, backDriver].map((card, idx) => (
            <div key={idx} className="src-card">
              <div className="src-head">
                <div className="src-title">{card.title}</div>
                <div className="src-scale">{card.scale}</div>
              </div>
              <div className="src-sub">{card.sub}</div>
              <div className="src-bar">
                {card.segments.map((seg, i) => (
                  <span
                    key={i}
                    style={{
                      width: `${seg.pct}%`,
                      background: seg.color,
                      color: seg.textOnLight ? "var(--ink-2)" : "#fff",
                    }}
                  >
                    {seg.pct}
                  </span>
                ))}
              </div>
              <div className="src-legend">
                {card.segments.map((seg, i) => (
                  <span key={i} className="src-li">
                    <span className="dot" style={{ background: seg.color }} />
                    {seg.name}
                    <span className="c">{seg.pct}</span>
                  </span>
                ))}
              </div>
              <div className="src-note">{card.note}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
